mapper.select:
SELECT 
FROM playlist
WHERE user_id = #{userId}
  AND is_deleted = false
ORDER BY created_at DESC
LIMIT #{offset}, #{limit}

mapper.insert:
INSERT INTO playlist (
    user_id, playlist_name, description, is_public,
    cover_image_url, like_count, is_imported, is_deleted,
    created_at, updated_at, created_by, updated_by
) VALUES (
    #{userId}, #{playlistName}, #{description}, #{isPublic},
    #{coverImageUrl}, #{likeCount}, #{isImported}, false,
    NOW(), NOW(), #{createdBy}, #{updatedBy}
)

mapper.select:
SELECT COUNT(*) > 0
FROM playlist_item
WHERE playlist_id = #{playlistId}
  AND movie_id = #{movieId}

SELECT playlist_item_id, playlist_id, movie_id, sort_order, added_at,
       created_at, updated_at
FROM playlist_item
WHERE playlist_id = #{playlistId}
  AND movie_id = #{movieId}
LIMIT 1

mapper.update:
UPDATE playlist_item
SET sort_order = sort_order - 1,
    updated_at = NOW()
WHERE playlist_id = #{playlistId}
  AND sort_order > #{deletedSortOrder}

